{
  "name": "Luggage Deposit Rome - Booking",
  "description": "A professional booking platform for luggage storage in Rome, featuring a seamless interface for selecting bag sizes, dates, and secure payments.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum BagSize {
  SMALL = 'Small',
  MEDIUM = 'Medium',
  LARGE = 'Large'
}

export interface BookingData {
  size: BagSize;
  quantity: number;
  dropOffDate: string;
  pickUpDate: string;
  customerName: string;
  customerEmail: string;
}

export interface PricingRule {
  size: BagSize;
  pricePerDay: number;
  description: string;
}

export interface BookingResult extends BookingData {
  billableDays: number;
  totalPrice: number;
  stripePaymentId: string;
  status: 'pending' | 'success' | 'failed';
}

import { BagSize, PricingRule } from './types';

export const PRICING_RULES: Record<BagSize, PricingRule> = {
  [BagSize.SMALL]: {
    size: BagSize.SMALL,
    pricePerDay: 5,
    description: 'Up to 10kg (Hand luggage style)'
  },
  [BagSize.MEDIUM]: {
    size: BagSize.MEDIUM,
    pricePerDay: 6,
    description: '10kg - 23kg (Standard suitcase)'
  },
  [BagSize.LARGE]: {
    size: BagSize.LARGE,
    pricePerDay: 7,
    description: 'Over 23kg (Large or oversized)'
  }
};

export const CONTACT_EMAIL = "info@luggagedepositrome.com";
export const LOCATION_ADDRESS = "Via Giovanni Giolitti, 34, 00185 Roma RM, Italy";

import React, { useState, useCallback } from 'react';
import { Header } from './components/Header';
import { Footer } from './components/Footer';
import { BookingForm } from './components/BookingForm';
import { SuccessView } from './components/SuccessView';
import { BookingResult } from './types';

const App: React.FC = () => {
  const [bookingResult, setBookingResult] = useState<BookingResult | null>(null);

  const handleBookingComplete = useCallback((result: BookingResult) => {
    setBookingResult(result);
    // In a real app, this would also handle scrolling to top or navigation
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, []);

  const handleReset = useCallback(() => {
    setBookingResult(null);
  }, []);

  return (
    <div className="flex flex-col min-h-screen">
      <Header />

      <main className="flex-grow pt-24 pb-12 px-4 md:px-8 max-w-7xl mx-auto w-full">
        {!bookingResult ? (
          <div className="animate-fade-in">
            <div className="text-center mb-10">
              <h1 className="text-3xl md:text-4xl font-extrabold text-rome-blue mb-4">
                Secure Luggage Storage in Rome
              </h1>
              <p className="text-gray-600 text-lg max-w-2xl mx-auto">
                Safe, affordable, and centrally located. Book your spot in seconds and explore the Eternal City hands-free.
              </p>
            </div>

            <BookingForm onComplete={handleBookingComplete} />
          </div>
        ) : (
          <SuccessView result={bookingResult} onReset={handleReset} />
        )}
      </main>

      <Footer />
    </div>
  );
};

export default App;

import React, { useState, useMemo } from 'react';
import { Calendar, Trash2, Plus, Minus, CreditCard, User, Mail } from 'lucide-react';
import { differenceInDays, parseISO, startOfDay, format, isValid, addDays } from 'date-fns';
import { BagSize, BookingData, BookingResult } from '../types';
import { PRICING_RULES } from '../constants';

interface BookingFormProps {
  onComplete: (result: BookingResult) => void;
}

export const BookingForm: React.FC<BookingFormProps> = ({ onComplete }) => {
  const [formData, setFormData] = useState<BookingData>({
    size: BagSize.MEDIUM,
    quantity: 1,
    dropOffDate: format(new Date(), 'yyyy-MM-dd'),
    pickUpDate: format(new Date(), 'yyyy-MM-dd'),
    customerName: '',
    customerEmail: '',
  });

  const [isLoading, setIsLoading] = useState(false);

  const billableDays = useMemo(() => {
    const start = startOfDay(parseISO(formData.dropOffDate));
    const end = startOfDay(parseISO(formData.pickUpDate));

    if (!isValid(start) || !isValid(end)) return 0;

    const diff = differenceInDays(end, start);
    return Math.max(diff + 1, 1);
  }, [formData.dropOffDate, formData.pickUpDate]);

  const pricePerDay = PRICING_RULES[formData.size].pricePerDay;
  const totalPrice = pricePerDay * formData.quantity * billableDays;

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const adjustQuantity = (amount: number) => {
    setFormData(prev => ({
      ...prev,
      quantity: Math.max(1, prev.quantity + amount)
    }));
  };

  const handlePayment = async () => {
    if (!formData.customerName || !formData.customerEmail) {
      alert("Please fill in your name and email.");
      return;
    }

    setIsLoading(true);

    // Mocking Stripe Checkout Redirection/Process
    // In a real environment, you'd call an API to get a sessionId
    await new Promise(resolve => setTimeout(resolve, 1500));

    const result: BookingResult = {
      ...formData,
      billableDays,
      totalPrice,
      stripePaymentId: 'ch_' + Math.random().toString(36).substr(2, 9),
      status: 'success'
    };

    setIsLoading(false);
    onComplete(result);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-start">
      {/* Form Area */}
      <div className="lg:col-span-2 space-y-6">
        <div className="bg-white p-6 md:p-8 rounded-2xl shadow-lg border border-gray-100">
          <h2 className="text-2xl font-bold text-rome-blue mb-8 flex items-center">
            <span className="bg-rome-blue text-white w-8 h-8 rounded-full inline-flex items-center justify-center mr-3 text-sm">1</span>
            Booking Details
          </h2>

          <div className="space-y-6">
            {/* Bag Size */}
            <div className="grid grid-cols-1 sm:grid-cols-3 gap-4">
              {(Object.values(BagSize)).map((size) => {
                const isSelected = formData.size === size;
                const rule = PRICING_RULES[size];
                return (
                  <button
                    key={size}
                    type="button"
                    onClick={() => setFormData(prev => ({ ...prev, size }))}
                    className={`p-4 border-2 rounded-xl text-left transition-all ${
                      isSelected 
                      ? 'border-rome-blue bg-blue-50 ring-2 ring-rome-blue ring-opacity-10' 
                      : 'border-gray-100 hover:border-gray-300'
                    }`}
                  >
                    <div className="font-bold text-lg text-rome-blue">{size}</div>
                    <div className="text-xs text-gray-500 mb-2 uppercase font-semibold">{rule.description}</div>
                    <div className="text-xl font-extrabold text-rome-accent">€{rule.pricePerDay}<span className="text-sm font-normal text-gray-400">/day</span></div>
                  </button>
                );
              })}
            </div>

            {/* Quantity and Dates */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
              <div className="space-y-2">
                <label className="text-sm font-bold text-gray-700 uppercase tracking-wider">Number of Bags</label>
                <div className="flex items-center space-x-4">
                  <button onClick={() => adjustQuantity(-1)} className="p-2 rounded-lg border border-gray-200 hover:bg-gray-50"><Minus className="w-5 h-5"/></button>
                  <span className="text-2xl font-bold text-rome-blue w-12 text-center">{formData.quantity}</span>
                  <button onClick={() => adjustQuantity(1)} className="p-2 rounded-lg border border-gray-200 hover:bg-gray-50"><Plus className="w-5 h-5"/></button>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div className="space-y-2">
                  <label className="text-sm font-bold text-gray-700 uppercase tracking-wider">Drop-off</label>
                  <div className="relative">
                    <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 pointer-events-none" />
                    <input 
                      type="date"
                      name="dropOffDate"
                      min={format(new Date(), 'yyyy-MM-dd')}
                      value={formData.dropOffDate}
                      onChange={handleInputChange}
                      className="w-full pl-10 pr-4 py-3 rounded-lg border border-gray-200 focus:outline-none focus:ring-2 focus:ring-rome-blue focus:border-transparent"
                    />
                  </div>
                </div>
                <div className="space-y-2">
                  <label className="text-sm font-bold text-gray-700 uppercase tracking-wider">Pick-up</label>
                  <div className="relative">
                    <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 pointer-events-none" />
                    <input 
                      type="date"
                      name="pickUpDate"
                      min={formData.dropOffDate}
                      value={formData.pickUpDate}
                      onChange={handleInputChange}
                      className="w-full pl-10 pr-4 py-3 rounded-lg border border-gray-200 focus:outline-none focus:ring-2 focus:ring-rome-blue focus:border-transparent"
                    />
                  </div>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="bg-white p-6 md:p-8 rounded-2xl shadow-lg border border-gray-100">
          <h2 className="text-2xl font-bold text-rome-blue mb-8 flex items-center">
            <span className="bg-rome-blue text-white w-8 h-8 rounded-full inline-flex items-center justify-center mr-3 text-sm">2</span>
            Customer Information
          </h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-sm font-bold text-gray-700 uppercase tracking-wider">Full Name</label>
              <div className="relative">
                <User className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                <input 
                  type="text"
                  name="customerName"
                  placeholder="John Doe"
                  value={formData.customerName}
                  onChange={handleInputChange}
                  className="w-full pl-10 pr-4 py-3 rounded-lg border border-gray-200 focus:outline-none focus:ring-2 focus:ring-rome-blue focus:border-transparent"
                />
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-sm font-bold text-gray-700 uppercase tracking-wider">Email Address</label>
              <div className="relative">
                <Mail className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                <input 
                  type="email"
                  name="customerEmail"
                  placeholder="john@example.com"
                  value={formData.customerEmail}
                  onChange={handleInputChange}
                  className="w-full pl-10 pr-4 py-3 rounded-lg border border-gray-200 focus:outline-none focus:ring-2 focus:ring-rome-blue focus:border-transparent"
                />
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Summary Area */}
      <div className="lg:sticky lg:top-24">
        <div className="bg-rome-blue text-white p-6 md:p-8 rounded-2xl shadow-xl overflow-hidden relative">
          <div className="absolute top-0 right-0 -mt-4 -mr-4 bg-rome-accent w-24 h-24 rounded-full opacity-20 blur-2xl"></div>

          <h3 className="font-montserrat font-bold text-xl mb-6 relative z-10">Booking Summary</h3>

          <div className="space-y-4 mb-8 relative z-10">
            <div className="flex justify-between items-center text-blue-100 pb-4 border-b border-blue-800">
              <span className="text-sm font-semibold uppercase tracking-wider">Bag Size</span>
              <span className="font-bold text-white">{formData.size} (€{pricePerDay}/day)</span>
            </div>
            <div className="flex justify-between items-center text-blue-100 pb-4 border-b border-blue-800">
              <span className="text-sm font-semibold uppercase tracking-wider">Quantity</span>
              <span className="font-bold text-white">{formData.quantity} {formData.quantity > 1 ? 'Bags' : 'Bag'}</span>
            </div>
            <div className="flex justify-between items-center text-blue-100 pb-4 border-b border-blue-800">
              <span className="text-sm font-semibold uppercase tracking-wider">Storage Duration</span>
              <span className="font-bold text-white">{billableDays} {billableDays > 1 ? 'Days' : 'Day'}</span>
            </div>
            <div className="pt-2 text-sm text-blue-200 italic">
              From {format(parseISO(formData.dropOffDate), 'MMM d, yyyy')} to {format(parseISO(formData.pickUpDate), 'MMM d, yyyy')}
            </div>
          </div>

          <div className="flex justify-between items-end mb-8">
            <span className="text-blue-100 font-bold uppercase tracking-widest text-sm">Total</span>
            <span className="text-4xl font-extrabold text-rome-accent">€{totalPrice.toFixed(2)}</span>
          </div>

          <button
            onClick={handlePayment}
            disabled={isLoading || !formData.customerName || !formData.customerEmail}
            className={`w-full py-4 rounded-xl font-bold flex items-center justify-center space-x-2 transition-all transform active:scale-95 ${
              isLoading || !formData.customerName || !formData.customerEmail
              ? 'bg-gray-500 cursor-not-allowed opacity-50'
              : 'bg-rome-accent hover:bg-orange-500 text-rome-blue shadow-lg'
            }`}
          >
            {isLoading ? (
              <div className="w-6 h-6 border-4 border-white border-t-transparent rounded-full animate-spin"></div>
            ) : (
              <>
                <CreditCard className="w-5 h-5" />
                <span>Pay & Reserve</span>
              </>
            )}
          </button>

          <p className="mt-4 text-center text-xs text-blue-300">
            Secure checkout powered by Stripe
          </p>
        </div>
      </div>

      {/* Mobile Sticky Button - Optional per request */}
      <div className="lg:hidden fixed bottom-0 left-0 right-0 p-4 bg-white border-t border-gray-200 z-40">
        <button
          onClick={handlePayment}
          disabled={isLoading || !formData.customerName || !formData.customerEmail}
          className={`w-full py-4 rounded-full font-bold flex items-center justify-center space-x-2 ${
            isLoading || !formData.customerName || !formData.customerEmail
            ? 'bg-gray-400'
            : 'bg-rome-blue text-white shadow-xl'
          }`}
        >
          {isLoading ? (
            <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
          ) : (
            <>
              <CreditCard className="w-5 h-5" />
              <span>Pay €{totalPrice.toFixed(2)}</span>
            </>
          )}
        </button>
      </div>
    </div>
  );
};

export enum BagSize {
  SMALL = 'Small',
  MEDIUM = 'Medium',
  LARGE = 'Large'
}

export interface BookingData {
  quantities: Record<BagSize, number>;
  dropOffDate: string;
  pickUpDate: string;
  customerName: string;
  customerEmail: string;
}

export interface PricingRule {
  size: BagSize;
  pricePerDay: number;
  description: string;
}

export interface BookingResult extends BookingData {
  billableDays: number;
  perDaySubtotal: number;
  totalPrice: number;
  stripePaymentId: string;
  status: 'pending' | 'success' | 'failed';
}

import React, { useState, useMemo } from 'react';
import { Calendar, Plus, Minus, CreditCard, User, Mail, Info } from 'lucide-react';
import { differenceInDays, parseISO, startOfDay, format, isValid, isBefore } from 'date-fns';
import { BagSize, BookingData, BookingResult } from '../types';
import { PRICING_RULES } from '../constants';

interface BookingFormProps {
  onComplete: (result: BookingResult) => void;
}

export const BookingForm: React.FC<BookingFormProps> = ({ onComplete }) => {
  const [formData, setFormData] = useState<BookingData>({
    quantities: {
      [BagSize.SMALL]: 0,
      [BagSize.MEDIUM]: 1, // Default to 1 medium
      [BagSize.LARGE]: 0,
    },
    dropOffDate: format(new Date(), 'yyyy-MM-dd'),
    pickUpDate: format(new Date(), 'yyyy-MM-dd'),
    customerName: '',
    customerEmail: '',
  });

  const [isLoading, setIsLoading] = useState(false);

  const billableDays = useMemo(() => {
    const start = startOfDay(parseISO(formData.dropOffDate));
    const end = startOfDay(parseISO(formData.pickUpDate));

    if (!isValid(start) || !isValid(end)) return 0;
    if (isBefore(end, start)) return 0;

    const diff = differenceInDays(end, start);
    return diff + 1; // Calendar days rule
  }, [formData.dropOffDate, formData.pickUpDate]);

  const perDaySubtotal = useMemo(() => {
    return Object.entries(formData.quantities).reduce((acc, [size, qty]) => {
      return acc + (PRICING_RULES[size as BagSize].pricePerDay * qty);
    }, 0);
  }, [formData.quantities]);

  const totalBags = useMemo(() => {
    return Object.values(formData.quantities).reduce((a, b) => a + b, 0);
  }, [formData.quantities]);

  const totalPrice = perDaySubtotal * billableDays;

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const adjustQuantity = (size: BagSize, amount: number) => {
    setFormData(prev => ({
      ...prev,
      quantities: {
        ...prev.quantities,
        [size]: Math.max(0, prev.quantities[size] + amount)
      }
    }));
  };

  const isFormValid = totalBags > 0 && billableDays > 0 && formData.customerName && formData.customerEmail;

  const handlePayment = async () => {
    if (!isFormValid) return;

    setIsLoading(true);
    // Simulate API call/Stripe redirect
    await new Promise(resolve => setTimeout(resolve, 1500));

    const result: BookingResult = {
      ...formData,
      billableDays,
      perDaySubtotal,
      totalPrice,
      stripePaymentId: 'ch_' + Math.random().toString(36).substr(2, 9),
      status: 'success'
    };

    setIsLoading(false);
    onComplete(result);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-8 items-start">
      {/* Form Area */}
      <div className="lg:col-span-2 space-y-6">
        <div className="bg-white p-6 md:p-8 rounded-2xl shadow-lg border border-gray-100">
          <h2 className="text-2xl font-bold text-rome-blue mb-8 flex items-center">
            <span className="bg-rome-blue text-white w-8 h-8 rounded-full inline-flex items-center justify-center mr-3 text-sm">1</span>
            Select Luggage
          </h2>

          <div className="space-y-4">
            {(Object.values(BagSize)).map((size) => {
              const rule = PRICING_RULES[size];
              const qty = formData.quantities[size];
              return (
                <div 
                  key={size}
                  className={`flex items-center justify-between p-4 md:p-6 border-2 rounded-xl transition-all ${
                    qty > 0 ? 'border-rome-blue bg-blue-50' : 'border-gray-100'
                  }`}
                >
                  <div className="flex-grow">
                    <div className="font-bold text-lg text-rome-blue">{size}</div>
                    <div className="text-sm text-gray-500">{rule.description}</div>
                    <div className="text-rome-accent font-bold mt-1">€{rule.pricePerDay} / day</div>
                  </div>

                  <div className="flex items-center space-x-4 bg-white rounded-lg border border-gray-200 p-1">
                    <button 
                      onClick={() => adjustQuantity(size, -1)}
                      className="p-2 rounded-md hover:bg-gray-100 text-rome-blue disabled:opacity-30"
                      disabled={qty === 0}
                    >
                      <Minus className="w-5 h-5"/>
                    </button>
                    <span className="text-xl font-bold text-rome-blue w-8 text-center">{qty}</span>
                    <button 
                      onClick={() => adjustQuantity(size, 1)}
                      className="p-2 rounded-md hover:bg-gray-100 text-rome-blue"
                    >
                      <Plus className="w-5 h-5"/>
                    </button>
                  </div>
                </div>
              );
            })}
          </div>

          {totalBags === 0 && (
            <div className="mt-4 flex items-center space-x-2 text-amber-600 bg-amber-50 p-3 rounded-lg text-sm">
              <Info className="w-4 h-4" />
              <span>Please select at least one bag to continue.</span>
            </div>
          )}
        </div>

        <div className="bg-white p-6 md:p-8 rounded-2xl shadow-lg border border-gray-100">
          <h2 className="text-2xl font-bold text-rome-blue mb-8 flex items-center">
            <span className="bg-rome-blue text-white w-8 h-8 rounded-full inline-flex items-center justify-center mr-3 text-sm">2</span>
            Dates & Info
          </h2>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
            <div className="space-y-2">
              <label className="text-sm font-bold text-gray-700 uppercase tracking-wider">Drop-off Date</label>
              <div className="relative">
                <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 pointer-events-none" />
                <input 
                  type="date"
                  name="dropOffDate"
                  min={format(new Date(), 'yyyy-MM-dd')}
                  value={formData.dropOffDate}
                  onChange={handleInputChange}
                  className="w-full pl-10 pr-4 py-3 rounded-lg border border-gray-200 focus:outline-none focus:ring-2 focus:ring-rome-blue focus:border-transparent"
                />
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-sm font-bold text-gray-700 uppercase tracking-wider">Pick-up Date</label>
              <div className="relative">
                <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 pointer-events-none" />
                <input 
                  type="date"
                  name="pickUpDate"
                  min={formData.dropOffDate}
                  value={formData.pickUpDate}
                  onChange={handleInputChange}
                  className="w-full pl-10 pr-4 py-3 rounded-lg border border-gray-200 focus:outline-none focus:ring-2 focus:ring-rome-blue focus:border-transparent"
                />
              </div>
              {billableDays === 0 && (
                <p className="text-xs text-red-500 font-medium">Pick-up cannot be before drop-off.</p>
              )}
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="space-y-2">
              <label className="text-sm font-bold text-gray-700 uppercase tracking-wider">Full Name</label>
              <div className="relative">
                <User className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                <input 
                  type="text"
                  name="customerName"
                  placeholder="John Doe"
                  value={formData.customerName}
                  onChange={handleInputChange}
                  className="w-full pl-10 pr-4 py-3 rounded-lg border border-gray-200 focus:outline-none focus:ring-2 focus:ring-rome-blue focus:border-transparent"
                />
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-sm font-bold text-gray-700 uppercase tracking-wider">Email Address</label>
              <div className="relative">
                <Mail className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                <input 
                  type="email"
                  name="customerEmail"
                  placeholder="john@example.com"
                  value={formData.customerEmail}
                  onChange={handleInputChange}
                  className="w-full pl-10 pr-4 py-3 rounded-lg border border-gray-200 focus:outline-none focus:ring-2 focus:ring-rome-blue focus:border-transparent"
                />
              </div>
            </div>
          </div>
        </div>
      </div>

      {/* Summary Area */}
      <div className="lg:sticky lg:top-24">
        <div className="bg-rome-blue text-white p-6 md:p-8 rounded-2xl shadow-xl overflow-hidden relative">
          <div className="absolute top-0 right-0 -mt-4 -mr-4 bg-rome-accent w-24 h-24 rounded-full opacity-20 blur-2xl"></div>

          <h3 className="font-montserrat font-bold text-xl mb-6 relative z-10">Booking Summary</h3>

          <div className="space-y-4 mb-8 relative z-10">
            {Object.entries(formData.quantities).map(([size, qty]) => {
              if (qty === 0) return null;
