                <div key={size} className="flex justify-between items-center pb-3 border-b border-gray-100">
                  <div className="text-sm font-medium text-gray-600">{size} <span className="text-gray-400">× {qty}</span></div>
                  <div className="font-bold text-gray-900 text-sm">€{(qty * rule.pricePerDay).toFixed(2)}/d</div>
                </div>
              );
            })}

            <div className="flex justify-between items-center text-green-900 font-bold">
              <span className="text-xs uppercase tracking-widest">Subtotal / Day</span>
              <span className="text-lg">€{perDaySubtotal.toFixed(2)}</span>
            </div>

            <div className="bg-gray-50 p-4 rounded-xl space-y-2">
              <div className="flex justify-between text-xs font-bold text-gray-500 uppercase tracking-wider">
                <span>Duration</span>
                <span>{billableDays} {billableDays === 1 ? 'Day' : 'Days'}</span>
              </div>
              <div className="text-xs text-gray-400 leading-relaxed italic">
                {billableDays > 0 ? (
                  <>From {format(parseISO(formData.dropOffDate), 'MMM d')} to {format(parseISO(formData.pickUpDate), 'MMM d, yyyy')}</>
                ) : (
                  <span className="text-red-400">Invalid range</span>
                )}
              </div>
            </div>
          </div>

          <div className="flex justify-between items-end mb-8 pt-4 border-t-2 border-dashed border-gray-100">
            <span className="text-gray-400 font-bold uppercase tracking-widest text-xs mb-1">Total Due</span>
            <span className="text-4xl font-black text-gray-900">€{totalPrice.toFixed(2)}</span>
          </div>

          <button
            onClick={handlePayment}
            disabled={isLoading || !isFormValid}
            className={`w-full py-4 rounded-xl font-bold flex items-center justify-center space-x-2 transition-all transform active:scale-95 ${
              isLoading || !isFormValid
              ? 'bg-gray-100 text-gray-400 cursor-not-allowed'
              : 'bg-green-900 hover:bg-black text-white shadow-xl'
            }`}
          >
            {isLoading ? (
              <div className="w-6 h-6 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
            ) : (
              <>
                <CreditCard className="w-4 h-4" />
                <span className="text-sm uppercase tracking-widest">Pay & Reserve</span>
              </>
            )}
          </button>

          <p className="mt-6 text-center text-[10px] text-gray-400 uppercase tracking-widest">
            Secure processing &bull; Instant Confirmation
          </p>
        </div>
      </div>

      {/* Mobile Sticky CTA */}
      <div className="lg:hidden fixed bottom-0 left-0 right-0 p-4 bg-white border-t border-gray-100 z-40 shadow-2xl">
        <button
          onClick={handlePayment}
          disabled={isLoading || !isFormValid}
          className={`w-full py-4 rounded-xl font-bold flex items-center justify-center space-x-2 transition-all ${
            isLoading || !isFormValid
            ? 'bg-gray-100 text-gray-300'
            : 'bg-green-900 text-white shadow-lg'
          }`}
        >
          {isLoading ? (
            <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
          ) : (
            <>
              <CreditCard className="w-4 h-4" />
              <span>PAY €{totalPrice.toFixed(2)}</span>
            </>
          )}
        </button>
      </div>
    </div>
  );
};

