import React, { useState, useCallback, useEffect } from 'react';
import { Header } from './components/Header';
import { Footer } from './components/Footer';
import { BookingForm } from './components/BookingForm';
import { SuccessView } from './components/SuccessView';
import { BookingResult } from './types';

const App: React.FC = () => {
  const [bookingResult, setBookingResult] = useState<BookingResult | null>(null);

  // Recover state from localStorage on mount
  useEffect(() => {
    const savedBooking = localStorage.getItem('ldr_latest_booking');
    if (savedBooking) {
      try {
        setBookingResult(JSON.parse(savedBooking));
      } catch (e) {
        console.error("Failed to parse saved booking", e);
        localStorage.removeItem('ldr_latest_booking');
      }
    }
  }, []);

  const handleBookingComplete = useCallback((result: BookingResult) => {
    // Generate a proper ID format: LDR-YYYYMMDD-XXXX
    const now = new Date();
    const dateStr = now.toISOString().split('T')[0].replace(/-/g, '');
    const randomPart = Math.random().toString(36).substring(2, 6).toUpperCase();
    const formattedId = `LDR-${dateStr}-${randomPart}`;

    const enhancedResult = { 
      ...result, 
      stripePaymentId: formattedId,
      timestamp: now.toISOString()
    };

    setBookingResult(enhancedResult);
    localStorage.setItem('ldr_latest_booking', JSON.stringify(enhancedResult));
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, []);

  const handleReset = useCallback(() => {
    setBookingResult(null);
    localStorage.removeItem('ldr_latest_booking');
  }, []);

  return (
    <div className="flex flex-col min-h-screen bg-white">
      {/* Hide header/footer during print */}
      <div className="print:hidden">
        <Header />
      </div>

      <main className="flex-grow pt-32 pb-20 px-4 md:px-8 max-w-7xl mx-auto w-full">
        {!bookingResult ? (
          <div className="animate-fade-in">
            <div className="text-center mb-16">
              <h1 className="text-4xl md:text-5xl font-black text-gray-900 mb-6 tracking-tight">
                Secure your luggage in Rome
              </h1>
              <p className="text-gray-500 text-lg max-w-2xl mx-auto leading-relaxed">
                Centralized storage near Termini Station. Safe, reliable, and instant booking.
              </p>
            </div>

            <BookingForm onComplete={handleBookingComplete} />
          </div>
        ) : (
          <SuccessView result={bookingResult} onReset={handleReset} />
        )}
      </main>

      <div className="print:hidden">
        <Footer />
      </div>
    </div>
  );
};

export default App;

export enum BagSize {
  SMALL = 'Small',
  MEDIUM = 'Medium',
  LARGE = 'Large'
}

export interface BookingData {
  quantities: Record<BagSize, number>;
  dropOffDate: string;
  pickUpDate: string;
  customerName: string;
  customerEmail: string;
  customerPhone: string;
}

export interface PricingRule {
  size: BagSize;
  pricePerDay: number;
  description: string;
}

export interface BookingResult extends BookingData {
  billableDays: number;
  perDaySubtotal: number;
  totalPrice: number;
  stripePaymentId: string;
  status: 'pending' | 'success' | 'failed';
  timestamp?: string;
}

import React, { useState, useMemo } from 'react';
import { Calendar, Plus, Minus, CreditCard, User, Mail, Phone, Info } from 'lucide-react';
import { differenceInDays, parseISO, startOfDay, format, isValid, isBefore } from 'date-fns';
import { BagSize, BookingData, BookingResult } from '../types';
import { PRICING_RULES } from '../constants';

interface BookingFormProps {
  onComplete: (result: BookingResult) => void;
}

export const BookingForm: React.FC<BookingFormProps> = ({ onComplete }) => {
  const [formData, setFormData] = useState<BookingData>({
    quantities: {
      [BagSize.SMALL]: 0,
      [BagSize.MEDIUM]: 1, 
      [BagSize.LARGE]: 0,
    },
    dropOffDate: format(new Date(), 'yyyy-MM-dd'),
    pickUpDate: format(new Date(), 'yyyy-MM-dd'),
    customerName: '',
    customerEmail: '',
    customerPhone: '',
  });

  const [isLoading, setIsLoading] = useState(false);

  const billableDays = useMemo(() => {
    const start = startOfDay(parseISO(formData.dropOffDate));
    const end = startOfDay(parseISO(formData.pickUpDate));

    if (!isValid(start) || !isValid(end)) return 0;
    if (isBefore(end, start)) return 0;

    const diff = differenceInDays(end, start);
    return diff + 1;
  }, [formData.dropOffDate, formData.pickUpDate]);

  const perDaySubtotal = useMemo(() => {
    return (Object.entries(formData.quantities) as [BagSize, number][]).reduce((acc: number, [size, qty]: [BagSize, number]) => {
      return acc + (PRICING_RULES[size].pricePerDay * qty);
    }, 0);
  }, [formData.quantities]);

  const totalBags = useMemo(() => {
    return (Object.values(formData.quantities) as number[]).reduce((a: number, b: number) => a + b, 0);
  }, [formData.quantities]);

  const totalPrice = perDaySubtotal * billableDays;

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const { name, value } = e.target;
    setFormData(prev => ({ ...prev, [name]: value }));
  };

  const adjustQuantity = (size: BagSize, amount: number) => {
    setFormData(prev => ({
      ...prev,
      quantities: {
        ...prev.quantities,
        [size]: Math.max(0, prev.quantities[size] + amount)
      }
    }));
  };

  // Name, Email, and Phone are now obligatory (along with bags and valid dates)
  const isFormValid = totalBags > 0 && billableDays > 0 && formData.customerName.trim() !== '' && formData.customerEmail.trim() !== '' && formData.customerPhone.trim() !== '';

  const handlePayment = async () => {
    if (!isFormValid) return;
    setIsLoading(true);
    await new Promise(resolve => setTimeout(resolve, 1500));

    const result: BookingResult = {
      ...formData,
      billableDays,
      perDaySubtotal,
      totalPrice,
      stripePaymentId: 'ch_' + Math.random().toString(36).substr(2, 9),
      status: 'success'
    };
    setIsLoading(false);
    onComplete(result);
  };

  return (
    <div className="grid grid-cols-1 lg:grid-cols-3 gap-10 items-start">
      {/* Form Area */}
      <div className="lg:col-span-2 space-y-10">
        <section>
          <h2 className="text-xl font-bold text-gray-900 mb-6 flex items-center">
            <span className="w-1.5 h-6 bg-green-900 rounded-full mr-3"></span>
            1. Select your luggage
          </h2>

          <div className="space-y-4">
            {(Object.values(BagSize)).map((size) => {
              const rule = PRICING_RULES[size];
              const qty = formData.quantities[size];
              return (
                <div 
                  key={size}
                  className={`flex items-center justify-between p-6 border rounded-2xl transition-all ${
                    qty > 0 ? 'border-green-900 bg-green-50/50 shadow-sm' : 'border-gray-200 hover:border-gray-300'
                  }`}
                >
                  <div className="flex-grow">
                    <div className="font-bold text-gray-900">{size}</div>
                    <div className="text-sm text-gray-500 mt-1">{rule.description}</div>
                    <div className="text-green-900 font-bold mt-2 text-sm">€{rule.pricePerDay} / day</div>
                  </div>

                  <div className="flex items-center space-x-4 bg-white rounded-xl border border-gray-200 p-1.5">
                    <button 
                      onClick={() => adjustQuantity(size, -1)}
                      className="p-1.5 rounded-lg hover:bg-gray-100 text-gray-900 disabled:opacity-20"
                      disabled={qty === 0}
                    >
                      <Minus className="w-4 h-4"/>
                    </button>
                    <span className="text-lg font-bold text-gray-900 w-6 text-center">{qty}</span>
                    <button 
                      onClick={() => adjustQuantity(size, 1)}
                      className="p-1.5 rounded-lg hover:bg-gray-100 text-gray-900"
                    >
                      <Plus className="w-4 h-4"/>
                    </button>
                  </div>
                </div>
              );
            })}
          </div>
        </section>

        <section>
          <h2 className="text-xl font-bold text-gray-900 mb-6 flex items-center">
            <span className="w-1.5 h-6 bg-green-900 rounded-full mr-3"></span>
            2. Storage dates & contact
          </h2>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
            <div className="space-y-2">
              <label className="text-xs font-bold text-gray-500 uppercase tracking-widest">Drop-off</label>
              <div className="relative">
                <Calendar className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 pointer-events-none" />
                <input 
                  type="date"
                  name="dropOffDate"
                  min={format(new Date(), 'yyyy-MM-dd')}
                  value={formData.dropOffDate}
                  onChange={handleInputChange}
                  className="w-full pl-12 pr-4 py-3.5 rounded-xl border border-gray-200 focus:outline-none focus:ring-2 focus:ring-green-900/10 focus:border-green-900 text-sm"
                />
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-xs font-bold text-gray-500 uppercase tracking-widest">Pick-up</label>
              <div className="relative">
                <Calendar className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400 pointer-events-none" />
                <input 
                  type="date"
                  name="pickUpDate"
                  min={formData.dropOffDate}
                  value={formData.pickUpDate}
                  onChange={handleInputChange}
                  className="w-full pl-12 pr-4 py-3.5 rounded-xl border border-gray-200 focus:outline-none focus:ring-2 focus:ring-green-900/10 focus:border-green-900 text-sm"
                />
              </div>
            </div>
          </div>

          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="md:col-span-2 space-y-2">
              <label className="text-xs font-bold text-gray-500 uppercase tracking-widest">Full Name (Obligatory)</label>
              <div className="relative">
                <User className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                <input 
                  type="text"
                  name="customerName"
                  placeholder="John Doe"
                  required
                  value={formData.customerName}
                  onChange={handleInputChange}
                  className="w-full pl-12 pr-4 py-3.5 rounded-xl border border-gray-200 focus:outline-none focus:ring-2 focus:ring-green-900/10 focus:border-green-900 text-sm"
                />
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-xs font-bold text-gray-500 uppercase tracking-widest">Email (Obligatory)</label>
              <div className="relative">
                <Mail className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                <input 
                  type="email"
                  name="customerEmail"
                  placeholder="john@example.com"
                  required
                  value={formData.customerEmail}
                  onChange={handleInputChange}
                  className="w-full pl-12 pr-4 py-3.5 rounded-xl border border-gray-200 focus:outline-none focus:ring-2 focus:ring-green-900/10 focus:border-green-900 text-sm"
                />
              </div>
            </div>
            <div className="space-y-2">
              <label className="text-xs font-bold text-gray-500 uppercase tracking-widest">Phone Number (Obligatory)</label>
              <div className="relative">
                <Phone className="absolute left-4 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                <input 
                  type="tel"
                  name="customerPhone"
                  placeholder="+39 3XX XXX XXXX"
                  required
                  value={formData.customerPhone}
                  onChange={handleInputChange}
                  className="w-full pl-12 pr-4 py-3.5 rounded-xl border border-gray-200 focus:outline-none focus:ring-2 focus:ring-green-900/10 focus:border-green-900 text-sm"
                />
              </div>
            </div>
          </div>
        </section>
      </div>

      {/* Summary Area */}
      <div className="lg:sticky lg:top-24">
        <div className="bg-white border-2 border-green-900 p-8 rounded-3xl shadow-sm relative overflow-hidden">
          <div className="absolute top-0 right-0 w-24 h-24 bg-green-50 rounded-full -mr-12 -mt-12"></div>

          <h3 className="font-bold text-lg mb-8 text-gray-900 relative z-10">Booking Summary</h3>

          <div className="space-y-6 mb-8 relative z-10">
            {(Object.entries(formData.quantities) as [BagSize, number][]).map(([size, qty]) => {
              if (qty === 0) return null;
              const rule = PRICING_RULES[size];
              return (
                <div key={size} className="flex justify-between items-center pb-3 border-b border-gray-100">
                  <div className="text-sm font-medium text-gray-600">{size} <span className="text-gray-400">× {qty}</span></div>
                  <div className="font-bold text-gray-900 text-sm">€{(qty * rule.pricePerDay).toFixed(2)}/d</div>
                </div>
              );
            })}

            <div className="flex justify-between items-center text-green-900 font-bold">
              <span className="text-xs uppercase tracking-widest">Subtotal / Day</span>
              <span className="text-lg">€{perDaySubtotal.toFixed(2)}</span>
            </div>

            <div className="bg-gray-50 p-4 rounded-xl space-y-2">
              <div className="flex justify-between text-xs font-bold text-gray-500 uppercase tracking-wider">
                <span>Duration</span>
                <span>{billableDays} {billableDays === 1 ? 'Day' : 'Days'}</span>
              </div>
              <div className="text-xs text-gray-400 leading-relaxed italic">
                {billableDays > 0 ? (
                  <>From {format(parseISO(formData.dropOffDate), 'MMM d')} to {format(parseISO(formData.pickUpDate), 'MMM d, yyyy')}</>
                ) : (
                  <span className="text-red-400">Invalid range</span>
                )}
              </div>
            </div>
          </div>

          <div className="flex justify-between items-end mb-8 pt-4 border-t-2 border-dashed border-gray-100">
            <span className="text-gray-400 font-bold uppercase tracking-widest text-xs mb-1">Total Due</span>
            <span className="text-4xl font-black text-gray-900">€{totalPrice.toFixed(2)}</span>
          </div>

          <button
            onClick={handlePayment}
            disabled={isLoading || !isFormValid}
            className={`w-full py-4 rounded-xl font-bold flex items-center justify-center space-x-2 transition-all transform active:scale-95 ${
              isLoading || !isFormValid
              ? 'bg-gray-100 text-gray-400 cursor-not-allowed'
              : 'bg-green-900 hover:bg-black text-white shadow-xl'
            }`}
          >
            {isLoading ? (
              <div className="w-6 h-6 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
            ) : (
              <>
                <CreditCard className="w-4 h-4" />
                <span className="text-sm uppercase tracking-widest">Pay & Reserve</span>
              </>
            )}
          </button>

          {!isFormValid && totalBags > 0 && billableDays > 0 && (
            <p className="mt-4 text-center text-[10px] text-red-500 uppercase tracking-widest font-bold">
              Please fill in all contact details
            </p>
          )}

          <p className="mt-6 text-center text-[10px] text-gray-400 uppercase tracking-widest">
            Secure processing & bull; Instant Confirmation
          </p>
        </div>
      </div>

      {/* Mobile Sticky CTA */}
      <div className="lg:hidden fixed bottom-0 left-0 right-0 p-4 bg-white border-t border-gray-100 z-40 shadow-2xl">
        <button
          onClick={handlePayment}
          disabled={isLoading || !isFormValid}
          className={`w-full py-4 rounded-xl font-bold flex items-center justify-center space-x-2 transition-all ${
            isLoading || !isFormValid
            ? 'bg-gray-100 text-gray-300'
            : 'bg-green-900 text-white shadow-lg'
          }`}
        >
          {isLoading ? (
            <div className="w-5 h-5 border-2 border-white border-t-transparent rounded-full animate-spin"></div>
          ) : (
            <>
              <CreditCard className="w-4 h-4" />
              <span>PAY €{totalPrice.toFixed(2)}</span>
            </>
          )}
        </button>
      </div>
    </div>
  );
};

export enum BagSize {
  SMALL = 'Small',
  MEDIUM = 'Medium',
  LARGE = 'Large'
}

export type Language = 'en' | 'it';

export interface BookingData {
  quantities: Record<BagSize, number>;
  dropOffDate: string;
  pickUpDate: string;
  customerName: string;
  customerEmail: string;
  customerPhone: string;
}

export interface PricingRule {
  size: BagSize;
  pricePerDay: number;
  description: string;
}

export interface BookingResult extends BookingData {
  billableDays: number;
  perDaySubtotal: number;
  totalPrice: number;
  stripePaymentId: string;
  status: 'pending' | 'success' | 'failed';
  timestamp?: string;
}

import React, { useState, useCallback, useEffect } from 'react';
import { Header } from './components/Header';
import { Footer } from './components/Footer';
import { BookingForm } from './components/BookingForm';
import { SuccessView } from './components/SuccessView';
import { BookingResult, Language } from './types';
import { TRANSLATIONS } from './translations';

const App: React.FC = () => {
  const [bookingResult, setBookingResult] = useState<BookingResult | null>(null);
  const [language, setLanguage] = useState<Language>('en');

  // Recover state from localStorage on mount
  useEffect(() => {
    const savedBooking = localStorage.getItem('ldr_latest_booking');
    if (savedBooking) {
      try {
        setBookingResult(JSON.parse(savedBooking));
      } catch (e) {
        console.error("Failed to parse saved booking", e);
        localStorage.removeItem('ldr_latest_booking');
      }
    }

    const savedLang = localStorage.getItem('ldr_language') as Language;
    if (savedLang && (savedLang === 'en' || savedLang === 'it')) {
      setLanguage(savedLang);
    }
  }, []);

  const toggleLanguage = useCallback((lang: Language) => {
    setLanguage(lang);
    localStorage.setItem('ldr_language', lang);
  }, []);

  const handleBookingComplete = useCallback((result: BookingResult) => {
    const now = new Date();
    const dateStr = now.toISOString().split('T')[0].replace(/-/g, '');
    const randomPart = Math.random().toString(36).substring(2, 6).toUpperCase();
    const formattedId = `LDR-${dateStr}-${randomPart}`;

    const enhancedResult = { 
      ...result, 
      stripePaymentId: formattedId,
      timestamp: now.toISOString()
    };

    setBookingResult(enhancedResult);
    localStorage.setItem('ldr_latest_booking', JSON.stringify(enhancedResult));
    window.scrollTo({ top: 0, behavior: 'smooth' });
  }, []);

  const handleReset = useCallback(() => {
    setBookingResult(null);
    localStorage.removeItem('ldr_latest_booking');
  }, []);

  const t = TRANSLATIONS[language];

  return (
    <div className="flex flex-col min-h-screen bg-white">
      <div className="print:hidden">
        <Header language={language} onLanguageToggle={toggleLanguage} />
      </div>

      <main className="flex-grow pt-32 pb-20 px-4 md:px-8 max-w-7xl mx-auto w-full">
        {!bookingResult ? (
          <div className="animate-fade-in">
            <div className="text-center mb-16">
              <h1 className="text-4xl md:text-5xl font-black text-gray-900 mb-6 tracking-tight">
                {t.booking.title}
              </h1>
              <p className="text-gray-500 text-lg max-w-2xl mx-auto leading-relaxed">
                {t.booking.subtitle}
              </p>
            </div>

            <BookingForm onComplete={handleBookingComplete} language={language} />
          </div>
        ) : (
          <SuccessView result={bookingResult} onReset={handleReset} language={language} />
        )}
      </main>

      <div className="print:hidden">
        <Footer language={language} />
      </div>
    </div>
  );
};

export default App;

