      cursorY -= 20;
      page.drawLine({ start: { x: 40, y: cursorY + 10 }, end: { x: width - 40, y: cursorY + 10 }, thickness: 0.5, color: borderGray });
    }
  });

  cursorY -= 20;
  const subtotalDaily = billableDays > 0 ? totalPrice / billableDays : 0;
