  [BagSize.MEDIUM]: {
    size: BagSize.MEDIUM,
    pricePerDay: 6,
    description: 'A medium suitcase. Max height: 70cm / 27 inches.'
  },
  [BagSize.LARGE]: {
    size: BagSize.LARGE,
    pricePerDay: 7,
    description: 'Anything larger than 70cm / 27 inches.'
  }
};

