import Stripe from 'stripe';
import * as jwt from 'jsonwebtoken';

const stripe = new Stripe(process.env.STRIPE_SECRET_KEY || '', {
  apiVersion: '2023-10-16' as any,
});

export default async function handler(req: any, res: any) {
  const { bookingId } = req.query;

  if (!bookingId) {
    return res.status(400).json({ error: 'Booking ID is required' });
  }

  const ISSUER_ID = process.env.GOOGLE_WALLET_ISSUER_ID;
  const SERVICE_ACCOUNT_EMAIL = process.env.GOOGLE_WALLET_SERVICE_ACCOUNT_EMAIL;
  const PRIVATE_KEY = process.env.GOOGLE_WALLET_PRIVATE_KEY?.replace(/\\n/g, '\n');

  if (!ISSUER_ID || !SERVICE_ACCOUNT_EMAIL || !PRIVATE_KEY) {
    return res.status(400).json({ 
      error: 'Google Wallet is not configured in environment variables.',
      details: {
        issuer: !!ISSUER_ID,
        email: !!SERVICE_ACCOUNT_EMAIL,
        key: !!PRIVATE_KEY
      }
    });
  }

  try {
    const session = await stripe.checkout.sessions.retrieve(bookingId);
    if (!session || session.payment_status !== 'paid') {
      return res.status(404).json({ error: 'Valid paid booking not found' });
    }

    const metadata = session.metadata || {};
    const quantities = JSON.parse(metadata.quantities || '{}');
    const customerName = metadata.customerName || 'Customer';
    const dropOffDate = metadata.dropOffDate || '';
    const dropOffTime = metadata.dropOffTime || '';
    const pickUpDate = metadata.pickUpDate || '';
    const pickUpTime = metadata.pickUpTime || '';
    const totalPrice = (session.amount_total || 0) / 100;

    const host = req.headers.host;
    const protocol = req.headers['x-forwarded-proto'] || 'https';
    const verifyUrl = `${protocol}://${host}/#/verify?bid=${bookingId}`;

    const bagsSummary = Object.entries(quantities)
      .filter(([_, qty]) => (qty as number) > 0)
      .map(([size, qty]) => `${size[0]}:${qty}`)
      .join(' ');

    const objectId = `${ISSUER_ID}.${bookingId.replace(/[^a-zA-Z0-9]/g, '_')}`;

    const claims = {
      iss: SERVICE_ACCOUNT_EMAIL,
      aud: 'google',
      typ: 'savetowallet',
      iat: Math.floor(Date.now() / 1000),
      payload: {
        genericObjects: [
          {
            id: objectId,
            classId: `${ISSUER_ID}.luggage_deposit_rome_booking`,
            genericType: 'GENERIC_TYPE_UNSPECIFIED',
            cardTitle: {
              defaultValue: {
                language: 'en',
                value: 'LUGGAGE DEPOSIT ROME'
              }
            },
            header: {
              defaultValue: {
                language: 'en',
                value: 'Luggage Storage'
              }
            },
            subheader: {
              defaultValue: {
                language: 'en',
                value: customerName
              }
            },
            logo: {
              sourceUri: {
                uri: 'https://cdn.shopify.com/s/files/1/0753/8144/0861/files/cropped-Untitled-design-2025-09-11T094640.576_1.png?v=1765462614'
              }
            },
            hexBackgroundColor: '#064e3b',
            barcode: {
              type: 'QR_CODE',
              value: verifyUrl,
              alternateText: `Ref: ${bookingId.substring(0, 8)}`
            },
            textModulesData: [
              {
                header: 'Booking ID',
                body: bookingId.substring(0, 12) + '...',
                id: 'booking_id'
              },
              {
                header: 'Drop-off',
                body: `${dropOffDate} @ ${dropOffTime}`,
                id: 'drop_off'
              },
              {
                header: 'Pick-up',
                body: `${pickUpDate} @ ${pickUpTime}`,
                id: 'pick_up'
              },
              {
                header: 'Luggage',
                body: bagsSummary,
                id: 'bags'
              }
            ],
            linksModuleData: {
              uris: [
                {
                  uri: 'https://maps.app.goo.gl/HxdE3NVp8KmcVcjt8',
                  description: 'V. Gioberti, 42, Rome'
                },
                {
                  uri: 'tel:+39064467843',
                  description: 'Contact Phone'
                }
              ]
            }
          }
        ]
      }
    };

    const token = jwt.sign(claims, PRIVATE_KEY, { algorithm: 'RS256' });
    const saveUrl = `https://pay.google.com/gp/v/save/${token}`;

    return res.status(200).json({ saveUrl });
  } catch (err: any) {
    console.error('Google Wallet generation error:', err);
    return res.status(500).json({ error: 'Failed to generate Wallet link', details: err.message });
  }
}

