import * as jwt from 'jsonwebtoken';

export default async function handler(req: any, res: any) {
  if (req.method !== 'POST') {
    return res.status(405).json({ error: 'Method not allowed. Use POST.' });
  }

  const { 
    bookingId, 
    small, 
    medium, 
    large, 
    dropOffDate, 
    pickUpDate, 
    customerEmail, 
    verifyUrl 
  } = req.body;

  if (!bookingId) {
    return res.status(400).json({ error: 'bookingId is required in the request body.' });
  }

  const ISSUER_ID = process.env.GOOGLE_WALLET_ISSUER_ID;
  const SERVICE_ACCOUNT_EMAIL = process.env.GOOGLE_WALLET_SERVICE_ACCOUNT_EMAIL;
  const PRIVATE_KEY = process.env.GOOGLE_WALLET_PRIVATE_KEY?.replace(/\\n/g, '\n');

  if (!ISSUER_ID || !SERVICE_ACCOUNT_EMAIL || !PRIVATE_KEY) {
    const missing = [];
    if (!ISSUER_ID) missing.push('GOOGLE_WALLET_ISSUER_ID');
    if (!SERVICE_ACCOUNT_EMAIL) missing.push('GOOGLE_WALLET_SERVICE_ACCOUNT_EMAIL');
    if (!PRIVATE_KEY) missing.push('GOOGLE_WALLET_PRIVATE_KEY');

    return res.status(500).json({ 
      error: 'Google Wallet configuration missing.',
      details: `Missing environment variables: ${missing.join(', ')}`
    });
  }

  try {
    const luggageParts = [];
    if (small > 0) luggageParts.push(`S:${small}`);
    if (medium > 0) luggageParts.push(`M:${medium}`);
    if (large > 0) luggageParts.push(`L:${large}`);
    const bagsSummary = luggageParts.join(' ') || 'No bags';

    // The objectId must follow the format: issuerId.uniqueId
    // uniqueId can only contain alphanumeric characters, underscores, or hyphens.
    const safeBookingId = bookingId.replace(/[^a-zA-Z0-9-_]/g, '_');
    const objectId = `${ISSUER_ID}.${safeBookingId}`;

    const claims = {
      iss: SERVICE_ACCOUNT_EMAIL,
      aud: 'google',
      typ: 'savetowallet',
      iat: Math.floor(Date.now() / 1000),
      payload: {
        genericObjects: [
          {
            id: objectId,
            classId: `${ISSUER_ID}.luggage_deposit_rome_booking`,
            genericType: 'GENERIC_TYPE_UNSPECIFIED',
            cardTitle: {
              defaultValue: {
                language: 'en',
                value: 'LUGGAGE DEPOSIT ROME'
              }
            },
            header: {
              defaultValue: {
                language: 'en',
                value: 'Luggage Storage'
              }
            },
            subheader: {
              defaultValue: {
                language: 'en',
                value: customerEmail || 'Customer'
              }
            },
            logo: {
              sourceUri: {
                uri: 'https://cdn.shopify.com/s/files/1/0753/8144/0861/files/cropped-Untitled-design-2025-09-11T094640.576_1.png?v=1765462614'
              }
            },
            hexBackgroundColor: '#064e3b',
            barcode: {
              type: 'QR_CODE',
              value: verifyUrl,
              alternateText: `Ref: ${bookingId.substring(0, 8)}`
            },
            textModulesData: [
              {
                header: 'Booking ID',
                body: bookingId.substring(0, 16) + '...',
                id: 'booking_id'
              },
              {
                header: 'Drop-off',
                body: dropOffDate || 'N/A',
                id: 'drop_off'
              },
              {
                header: 'Pick-up',
                body: pickUpDate || 'N/A',
                id: 'pick_up'
              },
              {
                header: 'Luggage',
                body: bagsSummary,
                id: 'bags'
              }
            ],
            linksModuleData: {
              uris: [
                {
                  uri: 'https://maps.app.goo.gl/HxdE3NVp8KmcVcjt8',
                  description: 'V. Gioberti, 42, Rome'
                },
                {
                  uri: 'tel:+39064467843',
                  description: 'Contact Phone'
                }
              ]
            }
          }
        ]
      }
    };

    // Google Wallet JWT flow: If the object with this ID already exists,
    // Google will automatically update (PATCH) it when the user saves.
    const token = jwt.sign(claims, PRIVATE_KEY, { algorithm: 'RS256' });
    const saveUrl = `https://pay.google.com/gp/v/save/${token}`;

    return res.status(200).json({ saveUrl, objectId });
  } catch (err: any) {
    console.error('Google Wallet generation error:', err);
    return res.status(500).json({ 
      error: 'Failed to generate Wallet link', 
      details: err.message 
    });
  }
}

