        <h2 className="text-white text-xl font-black uppercase tracking-tight">{t.verify.valid}</h2>
        <p className="text-green-300 text-[10px] font-bold uppercase tracking-widest mt-1">ID: {sessionId.substring(0, 12)}...</p>
