      large: quantities.Large || 0,
    },
    totalPaid: (session.amount_total || 0) / 100,
    currency: session.currency?.toUpperCase() || 'EUR',
    status: 'paid',
    notes: '',
  };

  try {
    await db.collection('bookings').doc(bookingRef).set(bookingData, { merge: true });
