export default async function handler(req: any, res: any) {
  if (req.method !== 'POST') {
    return res.status(405).end('Method Not Allowed');
  }

  const sig = req.headers['stripe-signature'];
  const buf = await readRawBody(req);
  let event;

  try {
    event = stripe.webhooks.constructEvent(
      buf,
      sig,
      process.env.STRIPE_WEBHOOK_SECRET || ''
    );
  } catch (err: any) {
    console.error(`[WEBHOOK] Signature Error: ${err.message}`);
    return res.status(400).send(`Webhook Error: ${err.message}`);
  }

  // Once verified, always aim for 200 to keep Stripe happy.
  console.log(`[WEBHOOK] Event: ${event.type} | ID: ${event.id}`);

  if (event.type === 'checkout.session.completed') {
    const session = event.data.object as Stripe.Checkout.Session;
    const bookingRef = session.metadata?.bookingRef || 'UNKNOWN';
    console.log(`[WEBHOOK] Session Paid: ${session.id} | Ref: ${bookingRef} | Status: ${session.payment_status}`);

    if (session.payment_status === 'paid') {
      // Fire-and-forget logic with internal error handling
      try {
        await saveBookingToFirestore(session);
      } catch (e) {
        console.error(`[WEBHOOK] Firestore write failed:`, e);
      }

      try {
        await handleSuccessfulPayment(session);
        console.log(`[WEBHOOK] Emails processed for #${bookingRef}`);
      } catch (e) {
        console.error(`[WEBHOOK] Email handling failed:`, e);
      }
    }
  }

  res.status(200).json({ received: true });
}

async function handleSuccessfulPayment(session: Stripe.Checkout.Session) {
  const metadata = session.metadata || {};
  const customerEmail = session.customer_details?.email;
  const customerName = metadata.customerName || '—';
  const dropOffDate = metadata.dropOffDate || '—';
  const dropOffTime = metadata.dropOffTime || '—';
  const pickUpDate = metadata.pickUpDate || '—';
  const pickUpTime = metadata.pickUpTime || '—';
  const billableDays = metadata.billableDays || '—';
  const siteUrl = metadata.siteUrl || 'https://booking.luggagedepositrome.com';
  const quantities = safeParseQuantities(metadata.quantities);
  const totalPrice = (session.amount_total || 0) / 100;
  const bookingRef = metadata.bookingRef || session.id.substring(session.id.length - 8).toUpperCase();

  let pdfBuffer: Buffer | null = null;
  try {
    pdfBuffer = await generateBookingPdfBuffer(session);
  } catch (err) {
    console.error('[EMAIL] PDF generation error:', err);
  }

  const commonStyles = `font-family: sans-serif; line-height: 1.6; color: #111827;`;
  const formatEmailDate = (d: string) => { try { return format(parseISO(d), 'dd MMM yyyy'); } catch { return d; } };

  const customerHtml = `
    <div style="${commonStyles} background-color: #f9fafb; padding: 20px;">
      <h1>Booking Confirmed!</h1>
      <p>Hi ${customerName}, your reference is <b>#${bookingRef}</b>.</p>
      <p>Drop-off: ${formatEmailDate(dropOffDate)} at ${dropOffTime}</p>
      <p>Pick-up: ${formatEmailDate(pickUpDate)} at ${pickUpTime}</p>
      <p>Total Paid: €${totalPrice.toFixed(2)}</p>
    </div>
  `;

  try {
    const attachments = pdfBuffer ? [{ filename: `booking-${bookingRef}.pdf`, content: pdfBuffer }] : [];
    if (customerEmail) {
      await resend.emails.send({
        from: process.env.EMAIL_FROM || 'onboarding@resend.dev',
        to: customerEmail,
        subject: `Confirmed: Luggage Deposit Rome (#${bookingRef})`,
        html: customerHtml,
        attachments
      });
      console.log(`[EMAIL] Sent to customer: ${customerEmail}`);
    }

    await resend.emails.send({
      from: process.env.EMAIL_FROM || 'onboarding@resend.dev',
      to: process.env.EMAIL_TO_OWNER || 'valigeriagioberti@gmail.com',
      subject: `New Paid Booking (#${bookingRef})`,
      html: `<p>New booking for ${customerName}. Total: €${totalPrice.toFixed(2)}</p>`,
      attachments
    });
    console.log(`[EMAIL] Sent to owner.`);
  } catch (error) {
    console.error('[EMAIL] Resend send error:', error);
  }
}

